	s.mu.Lock()
	s.executeCalled = true
	s.lastReq = req
	s.mu.Unlock()
	if s.executeFn != nil {
		return s.executeFn(req)
	}
	ch := make(chan agentlib.ServiceEvent, 1)
	ch <- agentlib.ServiceEvent{Type: "final", Data: []byte(`{"status":"success","final_text":"ok"}`)}
	close(ch)
	return ch, nil
}

